363: // UnmarshalYAML implements the yaml.Unmarshaler interface.
364: // NOTE: This method should not be used outside of this package. Use Load or LoadFile instead.
365: func (c *Config) UnmarshalYAML(unmarshal func(interface{}) error) error {
366: 	*c = DefaultConfig
367: 	// We want to set c to the defaults and then overwrite it with the input.
368: 	// To make unmarshal fill the plain data struct rather than calling UnmarshalYAML
369: 	// again, we have to hide it using a type indirection.
370: 	type plain Config
371: 	if err := unmarshal((*plain)(c)); err != nil {
372: 		return err
373: 	}
374: 
375: 	// If a global block was open but empty the default global config is overwritten.
376: 	// We have to restore it here.
377: 	if c.GlobalConfig.isZero() {
378: 		c.GlobalConfig = DefaultGlobalConfig
379: 	}
380: 
381: 	// If a runtime block was open but empty the default runtime config is overwritten.
382: 	// We have to restore it here.
383: 	if c.Runtime.isZero() {
384: 		c.Runtime = DefaultRuntimeConfig
385: 		// Use the GOGC env var value if the runtime section is empty.
386: 		c.Runtime.GoGC = getGoGCEnv()
387: 	}
388: 
389: 	for _, rf := range c.RuleFiles {
390: 		if !patRulePath.MatchString(rf) {
391: 			return fmt.Errorf("invalid rule file path %q", rf)
392: 		}
393: 	}
394: 
395: 	for _, sf := range c.ScrapeConfigFiles {
396: 		if !patRulePath.MatchString(sf) {
397: 			return fmt.Errorf("invalid scrape config file path %q", sf)
398: 		}
399: 	}
400: 
401: 	// Do global overrides and validation.
402: 	jobNames := map[string]struct{}{}
403: 	for _, scfg := range c.ScrapeConfigs {
404: 		if err := scfg.Validate(c.GlobalConfig); err != nil {
405: 			return err
406: 		}
407: 		if _, ok := jobNames[scfg.JobName]; ok {
408: 			return fmt.Errorf("found multiple scrape configs with job name %q", scfg.JobName)
409: 		}
410: 		jobNames[scfg.JobName] = struct{}{}
411: 	}
412: 
413: 	rwNames := map[string]struct{}{}
414: 	for _, rwcfg := range c.RemoteWriteConfigs {
415: 		if rwcfg == nil {
416: 			return errors.New("empty or null remote write config section")
417: 		}
418: 		// Skip empty names, we fill their name with their config hash in remote write code.
419: 		if _, ok := rwNames[rwcfg.Name]; ok && rwcfg.Name != "" {
420: 			return fmt.Errorf("found multiple remote write configs with job name %q", rwcfg.Name)
421: 		}
422: 		rwNames[rwcfg.Name] = struct{}{}
423: 	}
424: 	rrNames := map[string]struct{}{}
425: 	for _, rrcfg := range c.RemoteReadConfigs {
426: 		if rrcfg == nil {
427: 			return errors.New("empty or null remote read config section")
428: 		}
429: 		// Skip empty names, we fill their name with their config hash in remote read code.
430: 		if _, ok := rrNames[rrcfg.Name]; ok && rrcfg.Name != "" {
431: 			return fmt.Errorf("found multiple remote read configs with job name %q", rrcfg.Name)
432: 		}
433: 		rrNames[rrcfg.Name] = struct{}{}
434: 	}
435: 	return nil
436: }
